from __future__ import annotations

import json
import random
import re
import shutil
import subprocess
import time
from pathlib import Path
from typing import Any

from .core import envelope, load_json, now_ms, write_json
from .dss_workflow import SAFETY, _cap, _scan, _sha, _stats

ATTACH_FORBIDDEN_TOKENS = [
    "target.reset", "target.halt", "target.run", "loadProgram", "loadAndRun",
    "flash", "erase", "writeData", "writeWord", "writeRegister",
    "expression.write", "setValue", "GEL_Reset", "GEL_Halt", "GEL_Run",
]
GEL_SIDE_EFFECT_MARKERS = [
    "GEL Output",
    "DCSM Initialization",
    "out of reset and configured",
    "Memory Map Initialization Complete",
]


def _sid() -> str:
    return f"dss-attach-{time.strftime('%Y%m%d-%H%M%S')}-{random.randint(1000,9999)}"


def _session(workspace: Path, op: str, profile: Path | None) -> dict[str, Any]:
    sid = _sid()
    root = workspace / ".ai-debug-repair" / "sessions" / sid
    for child in ["scripts", "logs", "evidence"]:
        (root / child).mkdir(parents=True, exist_ok=True)
    write_json(root / "manifest.json", {
        "schema_version": "1.0",
        "session_id": sid,
        "operation": op,
        "created_ms": now_ms(),
        "workspace": str(workspace),
        "profile": str(profile) if profile else None,
        "mode": "attach-readonly",
    })
    return {"session_id": sid, "session_dir": root}


def _profile(profile_path: Path) -> tuple[dict[str, Any] | None, dict[str, Any] | None]:
    try:
        return load_json(profile_path), None
    except ValueError as exc:
        return None, envelope(False, "PROFILE_INVALID", str(exc))


def _evidence(sess: dict[str, Any]) -> dict[str, str]:
    root = sess["session_dir"]
    return {
        "session_dir": str(root),
        "manifest": str(root / "manifest.json"),
        "scripts_dir": str(root / "scripts"),
        "logs_dir": str(root / "logs"),
        "evidence_dir": str(root / "evidence"),
    }


def _result(ok: bool, code: str, message: str, data: dict[str, Any], sess: dict[str, Any], started: int, warnings: list[str] | None = None, cap: dict[str, Any] | None = None) -> dict[str, Any]:
    result = envelope(ok, code, message, data, warnings or [], [], started)
    result.update({
        "safety": dict(SAFETY),
        "capability_status": cap or {},
        "evidence": _evidence(sess),
        "session_id": sess["session_id"],
        "trace_id": sess["session_id"],
    })
    write_json(sess["session_dir"] / "result.json", result)
    return result


def _quote_js(value: str) -> str:
    return value.replace("\\", "/").replace("'", "\\'").replace('"', '\\"')


def _base(profile: dict[str, Any], body: str) -> str:
    ccxml = _quote_js(str(profile.get("target_config", "")))
    return "\n".join([
        "// Generated by airepair attach-readonly DSS template.",
        "// Allowed: setConfig, getListOfCPUs, openSession, target.connect, expression/memory read, target.disconnect, server.stop.",
        "// Forbidden: reset, halt, run, loadProgram, flash, erase, write memory/register/expression.",
        "importPackage(Packages.com.ti.debug.engine.scripting);",
        "importPackage(Packages.com.ti.ccstudio.scripting.environment);",
        "importPackage(Packages.java.lang);",
        "var scripting = ScriptingEnvironment.instance();",
        "var server = scripting.getServer('DebugServer.1');",
        f"server.setConfig('{ccxml}');",
        body,
        "try { server.stop(); } catch(ignore) {}",
        "",
    ])


def _resolve_core_js(profile: dict[str, Any]) -> str:
    core_path = str(profile.get("core_path", "")).strip()
    preferred = core_path or str(profile.get("core", "C28xx_CPU1"))
    preferred = _quote_js(preferred)
    return "\n".join([
        f"var preferredCore = '{preferred}';",
        "var cpus = server.getListOfCPUs();",
        "var corePath = null;",
        "for (var i = 0; i < cpus.length; i++) { if (String(cpus[i]) == preferredCore) { corePath = String(cpus[i]); break; } }",
        "if (corePath == null) { for (var j = 0; j < cpus.length; j++) { if (String(cpus[j]).indexOf(preferredCore) >= 0) { corePath = String(cpus[j]); break; } } }",
        "if (corePath == null && preferredCore == 'CPU1') { for (var k = 0; k < cpus.length; k++) { if (String(cpus[k]).indexOf('C28xx_CPU1') >= 0) { corePath = String(cpus[k]); break; } } }",
        "if (corePath == null) { throw 'No matching core path for ' + preferredCore; }",
    ])


def _symbol_load_js(profile: dict[str, Any], out_file: Path | None = None) -> str:
    symbol_file = str(out_file or profile.get("symbol_file") or profile.get("out_file") or "").strip()
    if not symbol_file:
        return ""
    return f"ds.symbol.load('{_quote_js(symbol_file)}');"


def _code_for_policy(script: str) -> str:
    return re.sub(r"(['\"])(?:\\.|(?!\1).)*\1", "''", script)


def _write_script(sess: dict[str, Any], name: str, script: str) -> tuple[Path | None, list[str]]:
    body = "\n".join(line for line in script.splitlines() if not line.strip().startswith("//"))
    policy_body = _code_for_policy(body)
    found = [token for token in ATTACH_FORBIDDEN_TOKENS if token.lower() in policy_body.lower()]
    found.extend(_scan(policy_body))
    found = sorted(set(found))
    if found:
        return None, found
    path = sess["session_dir"] / "scripts" / name
    path.write_text(script, encoding="utf-8")
    return path, []


def _run(profile: dict[str, Any], script: Path, sess: dict[str, Any], timeout: int = 30) -> tuple[bool, dict[str, Any]]:
    launcher = str(profile.get("dss_launcher", ""))
    if not Path(launcher).exists() and not shutil.which(launcher):
        return False, {"code": "DEPENDENCY_MISSING", "message": f"DSS launcher not found: {launcher}"}
    try:
        completed = subprocess.run([launcher, str(script)], text=True, capture_output=True, timeout=timeout, shell=False)
    except subprocess.TimeoutExpired:
        return False, {"code": "TIMEOUT", "message": f"DSS script timed out after {timeout}s", "stdout": "", "stderr": ""}
    stdout = completed.stdout or ""
    stderr = completed.stderr or ""
    (sess["session_dir"] / "logs" / "dss.stdout.log").write_text(stdout, encoding="utf-8", errors="replace")
    (sess["session_dir"] / "logs" / "dss.stderr.log").write_text(stderr, encoding="utf-8", errors="replace")
    parsed = _parse_markers(stdout)
    stderr_error = _stderr_has_script_error(stderr)
    parsed.update({
        "returncode": completed.returncode,
        "stdout_sha256": _sha(sess["session_dir"] / "logs" / "dss.stdout.log"),
        "stderr_sha256": _sha(sess["session_dir"] / "logs" / "dss.stderr.log"),
        "gel_side_effect_detected": _gel_detected(stdout),
        "stderr_error_detected": stderr_error,
    })
    if stderr_error:
        parsed.update({"ok": False, "code": "DSS_SCRIPT_EXCEPTION", "message": _first_error_line(stderr)})
    elif completed.returncode != 0 and parsed.get("code") == "OK":
        parsed["code"] = "DSS_COMMAND_FAILED"
    return completed.returncode == 0 and bool(parsed.get("ok", True)) and not stderr_error, parsed


def _stderr_has_script_error(stderr: str) -> bool:
    markers = ["WrappedException", "ScriptingException", "NullPointerException", "RhinoException", "org.mozilla.javascript", "java.lang."]
    return any(marker in stderr for marker in markers)


def _first_error_line(stderr: str) -> str:
    for raw in stderr.splitlines():
        line = raw.strip()
        if line and not line.startswith("SLF4J:"):
            return line
    return "DSS script error"


def _parse_markers(stdout: str) -> dict[str, Any]:
    values: list[str] = []
    in_values = False
    data: dict[str, Any] = {"ok": True, "code": "OK", "values": values}
    for raw in stdout.splitlines():
        line = raw.strip()
        if line.endswith("_ERROR"):
            data.update({"ok": False, "code": "DSS_ERROR", "message": line})
        elif line == "AI_DEBUG_CPU_LIST_BEGIN":
            in_values = True
        elif line == "AI_DEBUG_CPU_LIST_END":
            in_values = False
        elif line.startswith("AI_DEBUG_CORE_PATH:"):
            data["core_path"] = line.split(":", 1)[1]
        elif line == "AI_DEBUG_CONNECT_OK":
            data["connected"] = True
        elif line == "AI_DEBUG_DISCONNECT_OK":
            data["disconnected"] = True
        elif line.startswith("AI_DEBUG_EXPR_VALUE:"):
            data["expression_value"] = line.split(":", 1)[1]
        elif line.startswith("AI_DEBUG_SAMPLE:"):
            values.append(line.split(":", 1)[1])
        elif in_values:
            values.append(line)
    return data


def _gel_detected(stdout: str) -> bool:
    lower = stdout.lower()
    return any(marker.lower() in lower for marker in GEL_SIDE_EFFECT_MARKERS)


def _with_gel_policy(ok: bool, parsed: dict[str, Any], warnings: list[str]) -> tuple[bool, str, list[str]]:
    if parsed.get("gel_side_effect_detected"):
        warnings.append("CCS/GEL side-effect output detected; attach-readonly is not non-invasive with this target_config")
        return False, "AUTO_GEL_DETECTED", warnings
    return ok, "OK" if ok else parsed.get("code", "DSS_ERROR"), warnings


def attach_core_list(profile_path: Path, workspace: Path, execute: bool = False) -> dict[str, Any]:
    started = now_ms(); prof, err = _profile(profile_path); sess = _session(workspace, "dss.attach-readonly.core-list", profile_path)
    if err: return _result(False, "PROFILE_INVALID", err["message"], {}, sess, started)
    cap = _cap(prof)
    script = _base(prof, "print('AI_DEBUG_CPU_LIST_BEGIN'); var cpus=server.getListOfCPUs(); for(var i=0;i<cpus.length;i++){ print(String(cpus[i])); } print('AI_DEBUG_CPU_LIST_END');")
    path, bad = _write_script(sess, "attach_core_list.js", script)
    data = {"operation": "attach-readonly.core-list", "execute": execute, "script": str(path) if path else None, "device": prof.get("device"), "probe": prof.get("probe"), "core": prof.get("core"), "target_config": prof.get("target_config")}
    if bad: return _result(False, "POLICY_DENIED", "Generated DSS script contains forbidden tokens", {**data, "forbidden_tokens": bad}, sess, started, cap=cap)
    if not execute: return _result(True, "OK", "Attach-readonly core-list script generated", data, sess, started, ["not executed; add --execute to query DSS CPU paths"], cap)
    ok, parsed = _run(prof, path, sess, int(prof.get("connect_timeout_seconds", 20)) + 20)
    data["dss"] = parsed; data["core_paths"] = parsed.get("values", [])
    cap["core_list"] = "verified" if ok else "not_verified"
    return _result(ok, "OK" if ok else parsed.get("code", "DSS_ERROR"), "Attach-readonly core-list completed" if ok else "Attach-readonly core-list failed", data, sess, started, cap=cap)


def attach_derive_ccxml(profile_path: Path, workspace: Path, output: Path, execute: bool = False, disable_gel: bool = True) -> dict[str, Any]:
    started = now_ms(); prof, err = _profile(profile_path); sess = _session(workspace, "dss.attach-readonly.derive-ccxml", profile_path)
    if err: return _result(False, "PROFILE_INVALID", err["message"], {}, sess, started)
    cap = _cap(prof)
    source = Path(str(prof.get("target_config", "")))
    data = {"operation": "attach-readonly.derive-ccxml", "execute": execute, "source": str(source), "output": str(output), "disable_gel": disable_gel}
    if not source.exists():
        return _result(False, "TARGET_CONFIG_MISSING", f"target_config not found: {source}", data, sess, started, cap=cap)
    output.parent.mkdir(parents=True, exist_ok=True)
    script_body = "\n".join([
        "var editor = server.createTargetConfigurationEditor();",
        f"editor.setConfigFile('{_quote_js(str(output))}');",
        "editor.setOption('initialization script', '');" if disable_gel else "print('AI_DEBUG_DERIVE_NO_OPTION_CHANGE');",
        "editor.saveChanges();",
        "print('AI_DEBUG_DERIVE_CCXML_OK');",
    ])
    script = _base({**prof, "target_config": str(source)}, script_body)
    path, bad = _write_script(sess, "derive_ccxml.js", script)
    data["script"] = str(path) if path else None
    if bad: return _result(False, "POLICY_DENIED", "Generated DSS script contains forbidden tokens", {**data, "forbidden_tokens": bad}, sess, started, cap=cap)
    if not execute:
        return _result(True, "OK", "Attach-readonly ccxml derivation script generated", data, sess, started, ["not executed; add --execute to write derived ccxml"], cap)
    shutil.copyfile(source, output)
    ok, parsed = _run(prof, path, sess, 30)
    data["dss"] = parsed
    data["output_exists"] = output.exists()
    data["gel_file_empty_count"] = output.read_text(encoding="utf-8", errors="replace").count('id="GEL File"') if output.exists() else 0
    return _result(ok and output.exists(), "OK" if ok and output.exists() else parsed.get("code", "DSS_ERROR"), "Attach-readonly ccxml derived" if ok else "Attach-readonly ccxml derivation failed", data, sess, started, cap=cap)


def attach_connect_test(profile_path: Path, workspace: Path, execute: bool = False) -> dict[str, Any]:
    started = now_ms(); prof, err = _profile(profile_path); sess = _session(workspace, "dss.attach-readonly.connect-test", profile_path)
    if err: return _result(False, "PROFILE_INVALID", err["message"], {}, sess, started)
    cap = _cap(prof)
    body = "\n".join([_resolve_core_js(prof), "print('AI_DEBUG_CORE_PATH:' + corePath);", "var ds=server.openSession(corePath);", "print('AI_DEBUG_CONNECT_BEGIN');", "ds.target.connect();", "print('AI_DEBUG_CONNECT_OK');", "ds.target.disconnect();", "print('AI_DEBUG_DISCONNECT_OK');", "ds.terminate();"])
    script = _base(prof, body)
    path, bad = _write_script(sess, "attach_connect_test.js", script)
    data = {"operation": "attach-readonly.connect-test", "execute": execute, "script": str(path) if path else None, "device": prof.get("device"), "probe": prof.get("probe"), "core": prof.get("core"), "core_path": prof.get("core_path")}
    if bad: return _result(False, "POLICY_DENIED", "Generated DSS script contains forbidden tokens", {**data, "forbidden_tokens": bad}, sess, started, cap=cap)
    if not execute: return _result(True, "OK", "Attach-readonly connect script generated", data, sess, started, ["not executed; add --execute to connect hardware"], cap)
    ok, parsed = _run(prof, path, sess, int(prof.get("connect_timeout_seconds", 20)) + 30)
    warnings: list[str] = []
    ok, code, warnings = _with_gel_policy(ok, parsed, warnings)
    data["dss"] = parsed
    data["core_path_resolved"] = parsed.get("core_path")
    cap["debug_connection"] = "verified" if ok else "not_verified"
    cap["connect_disconnect"] = "verified" if ok and parsed.get("disconnected") else "not_verified"
    cap["realtime_debug"] = "candidate" if ok else "not_verified"
    return _result(ok, code, "Attach-readonly connect/disconnect completed" if ok else "Attach-readonly connect/disconnect failed", data, sess, started, warnings, cap)


def attach_read_expression(profile_path: Path, workspace: Path, expression: str, execute: bool = False) -> dict[str, Any]:
    started = now_ms(); prof, err = _profile(profile_path); sess = _session(workspace, "dss.attach-readonly.read-expression", profile_path)
    if err: return _result(False, "PROFILE_INVALID", err["message"], {}, sess, started)
    cap = _cap(prof)
    if expression not in prof.get("allowed_expressions", []):
        return _result(False, "POLICY_DENIED", f"expression is not listed in allowed_expressions: {expression}", {"expression": expression}, sess, started, cap=cap)
    expr = _quote_js(expression)
    body = "\n".join([_resolve_core_js(prof), "print('AI_DEBUG_CORE_PATH:' + corePath);", "var ds=server.openSession(corePath);", "ds.target.connect();", _symbol_load_js(prof), f"var value=ds.expression.evaluateToString('{expr}');", "print('AI_DEBUG_EXPR_VALUE:' + String(value));", "ds.target.disconnect();", "print('AI_DEBUG_DISCONNECT_OK');", "ds.terminate();"])
    script = _base(prof, body)
    path, bad = _write_script(sess, "attach_read_expression.js", script)
    data = {"operation": "attach-readonly.read-expression", "execute": execute, "script": str(path) if path else None, "expression": expression, "symbol_file": prof.get("symbol_file") or prof.get("out_file"), "device": prof.get("device"), "probe": prof.get("probe"), "core": prof.get("core")}
    if bad: return _result(False, "POLICY_DENIED", "Generated DSS script contains forbidden tokens", {**data, "forbidden_tokens": bad}, sess, started, cap=cap)
    if not execute: return _result(True, "OK", "Attach-readonly expression script generated", data, sess, started, ["not executed; add --execute to read hardware"], cap)
    ok, parsed = _run(prof, path, sess, int(prof.get("expression_timeout_seconds", 10)) + 30)
    warnings: list[str] = []
    ok, code, warnings = _with_gel_policy(ok, parsed, warnings)
    data["dss"] = parsed
    data["value"] = parsed.get("expression_value")
    cap["ram_read"] = "verified" if ok else "not_verified"
    if prof.get("symbol_file") or prof.get("out_file"):
        cap["symbol_load"] = "verified" if ok else "not_verified"
    return _result(ok, code, "Attach-readonly expression read completed" if ok else "Attach-readonly expression read failed", data, sess, started, warnings, cap)


def attach_monitor_address(profile_path: Path, workspace: Path, address: str, page: str, width: int, samples: int, interval_ms: int, execute: bool = False) -> dict[str, Any]:
    started = now_ms(); prof, err = _profile(profile_path); sess = _session(workspace, "dss.attach-readonly.monitor-address", profile_path)
    if err: return _result(False, "PROFILE_INVALID", err["message"], {}, sess, started)
    cap = _cap(prof)
    try:
        addr = int(str(address), 0)
    except ValueError:
        return _result(False, "ADDRESS_INVALID", f"invalid address: {address}", {"address": address}, sess, started, cap=cap)
    page_expr = "Memory.Page.DATA" if page.upper() == "DATA" else "Memory.Page.PROGRAM"
    body = "\n".join([_resolve_core_js(prof), "print('AI_DEBUG_CORE_PATH:' + corePath);", "var ds=server.openSession(corePath);", "ds.target.connect();", f"for(var i=0;i<{samples};i++){{ var v=ds.memory.readData({page_expr},{addr},{width},false); print('AI_DEBUG_SAMPLE:' + String(v)); Thread.sleep({interval_ms}); }}", "ds.target.disconnect();", "print('AI_DEBUG_DISCONNECT_OK');", "ds.terminate();"])
    script = _base(prof, body)
    path, bad = _write_script(sess, "attach_monitor_address.js", script)
    data = {"operation": "attach-readonly.monitor-address", "execute": execute, "script": str(path) if path else None, "address": hex(addr), "page": page.upper(), "width_bits": width, "samples": samples, "interval_ms": interval_ms, "device": prof.get("device"), "probe": prof.get("probe"), "core": prof.get("core")}
    if bad: return _result(False, "POLICY_DENIED", "Generated DSS script contains forbidden tokens", {**data, "forbidden_tokens": bad}, sess, started, cap=cap)
    if not execute:
        data.update(_stats([]))
        return _result(True, "OK", "Attach-readonly monitor-address script generated", data, sess, started, ["not executed; add --execute to sample hardware"], cap)
    ok, parsed = _run(prof, path, sess, max(30, samples * interval_ms // 1000 + 30))
    warnings: list[str] = []
    ok, code, warnings = _with_gel_policy(ok, parsed, warnings)
    stats = _stats(parsed.get("values", []))
    data.update(stats); data["dss"] = parsed
    (sess["session_dir"] / "evidence" / "samples.jsonl").write_text("\n".join(json.dumps({"index": i, "value": v}, ensure_ascii=False) for i, v in enumerate(stats["values"])) + "\n", encoding="utf-8")
    cap["ram_read"] = "verified" if ok else "not_verified"
    cap["repeated_read"] = "verified" if ok and samples > 1 else "not_verified"
    cap["changing_monitor"] = "verified" if ok and stats["changed"] else "not_verified"
    cap["realtime_debug"] = "candidate" if ok else "not_verified"
    return _result(ok, code, "Attach-readonly monitor-address completed" if ok else "Attach-readonly monitor-address failed", data, sess, started, warnings, cap)

def attach_monitor_symbol(profile_path: Path, workspace: Path, out_file: Path, symbol: str, samples: int, interval_ms: int, execute: bool = False) -> dict[str, Any]:
    started = now_ms(); prof, err = _profile(profile_path); sess = _session(workspace, "dss.attach-readonly.monitor-symbol", profile_path)
    if err: return _result(False, "PROFILE_INVALID", err["message"], {}, sess, started)
    cap = _cap(prof)
    if symbol not in prof.get("allowed_expressions", []):
        return _result(False, "POLICY_DENIED", f"symbol is not listed in allowed_expressions: {symbol}", {"symbol": symbol}, sess, started, cap=cap)
    sym = _quote_js(symbol)
    body = "\n".join([_resolve_core_js(prof), "print('AI_DEBUG_CORE_PATH:' + corePath);", "var ds=server.openSession(corePath);", "ds.target.connect();", _symbol_load_js(prof, out_file), f"for(var i=0;i<{samples};i++){{ var v=ds.expression.evaluateToString('{sym}'); print('AI_DEBUG_SAMPLE:' + String(v)); Thread.sleep({interval_ms}); }}", "ds.target.disconnect();", "print('AI_DEBUG_DISCONNECT_OK');", "ds.terminate();"])
    script = _base(prof, body)
    path, bad = _write_script(sess, "attach_monitor_symbol.js", script)
    data = {"operation": "attach-readonly.monitor-symbol", "execute": execute, "script": str(path) if path else None, "out_file": str(out_file), "out_sha256": _sha(out_file), "symbol": symbol, "samples": samples, "interval_ms": interval_ms, "device": prof.get("device"), "probe": prof.get("probe"), "core": prof.get("core")}
    if bad: return _result(False, "POLICY_DENIED", "Generated DSS script contains forbidden tokens", {**data, "forbidden_tokens": bad}, sess, started, cap=cap)
    if not execute:
        data.update(_stats([]))
        return _result(True, "OK", "Attach-readonly monitor-symbol script generated", data, sess, started, ["not executed; add --execute to sample hardware"], cap)
    ok, parsed = _run(prof, path, sess, max(30, samples * interval_ms // 1000 + 30))
    warnings: list[str] = []
    ok, code, warnings = _with_gel_policy(ok, parsed, warnings)
    stats = _stats(parsed.get("values", []))
    data.update(stats); data["dss"] = parsed
    (sess["session_dir"] / "evidence" / "samples.jsonl").write_text("\n".join(json.dumps({"index": i, "value": v}, ensure_ascii=False) for i, v in enumerate(stats["values"])) + "\n", encoding="utf-8")
    cap["ram_read"] = "verified" if ok else "not_verified"
    cap["symbol_load"] = "verified" if ok else "not_verified"
    cap["repeated_read"] = "verified" if ok and samples > 1 else "not_verified"
    cap["changing_monitor"] = "verified" if ok and stats["changed"] else "not_verified"
    cap["realtime_debug"] = "candidate" if ok else "not_verified"
    return _result(ok, code, "Attach-readonly monitor-symbol completed" if ok else "Attach-readonly monitor-symbol failed", data, sess, started, warnings, cap)
